from typing import List

class Solution:
    def numberOfSubmatrices(self, grid: List[List[str]]) -> int:
        n, m = len(grid), len(grid[0])
        # 2D prefix sum for 'X' and 'Y'
        prefix_x = [[0] * (m + 1) for _ in range(n + 1)]
        prefix_y = [[0] * (m + 1) for _ in range(n + 1)]

        for i in range(n):
            for j in range(m):
                prefix_x[i + 1][j + 1] = prefix_x[i][j + 1] + prefix_x[i + 1][j] - prefix_x[i][j] + (1 if grid[i][j] == 'X' else 0)
                prefix_y[i + 1][j + 1] = prefix_y[i][j + 1] + prefix_y[i + 1][j] - prefix_y[i][j] + (1 if grid[i][j] == 'Y' else 0)

        count = 0

        # Only consider submatrices that include grid[0][0]
        for i in range(n):
            for j in range(m):
                # Compute the number of 'X' and 'Y' in the submatrix from (0,0) to (i,j)
                x = prefix_x[i + 1][j + 1] - prefix_x[0][j + 1] - prefix_x[i + 1][0] + prefix_x[0][0]
                y = prefix_y[i + 1][j + 1] - prefix_y[0][j + 1] - prefix_y[i + 1][0] + prefix_y[0][0]
                if x == y and x > 0:
                    count += 1

        return count
